import React from 'react';
import { Link } from 'react-router-dom';
import { useTranslation } from 'react-i18next';
import { 
    Facebook, 
    Twitter, 
    Instagram, 
    Linkedin, 
    Youtube,
    ChevronUp,
    MapPin,
    Phone,
    Fax,
    Globe,
    Clock,
    GraduationCap
} from 'lucide-react';

const Footer = () => {
    const { t } = useTranslation();
    const currentYear = new Date().getFullYear();

    // Scroll to top function
    const scrollToTop = () => {
        window.scrollTo({ top: 0, behavior: 'smooth' });
    };

    const socialLinks = [
        { 
            icon: Facebook, 
            url: 'https://facebook.com/', 
            name: 'Facebook',
            color: 'hover:bg-blue-600 hover:text-white group-hover:scale-110',
            bgColor: 'bg-blue-50 hover:bg-blue-600'
        },
        { 
            icon: Twitter, 
            url: 'https://twitter.com/', 
            name: 'Twitter',
            color: 'hover:bg-sky-500 hover:text-white group-hover:scale-110',
            bgColor: 'bg-sky-50 hover:bg-sky-500'
        },
        { 
            icon: Instagram, 
            url: 'https://instagram.com/', 
            name: 'Instagram',
            color: 'hover:bg-pink-500 hover:text-white group-hover:scale-110',
            bgColor: 'bg-pink-50 hover:bg-pink-500'
        },
        { 
            icon: Linkedin, 
            url: 'https://linkedin.com/', 
            name: 'LinkedIn',
            color: 'hover:bg-blue-700 hover:text-white group-hover:scale-110',
            bgColor: 'bg-blue-50 hover:bg-blue-700'
        },
        { 
            icon: Youtube, 
            url: 'https://youtube.com/', 
            name: 'YouTube',
            color: 'hover:bg-red-600 hover:text-white group-hover:scale-110',
            bgColor: 'bg-red-50 hover:bg-red-600'
        }
    ];

    return (
        <footer className="bg-gradient-to-br from-slate-50 via-blue-50 to-indigo-100 border-t border-slate-200">
            {/* Decorative Top Wave */}
            <div className="relative overflow-hidden">
                <svg className="w-full h-12 text-white" viewBox="0 0 1200 120" preserveAspectRatio="none">
                    <path 
                        d="M321.39,56.44c58-10.79,114.16-30.13,172-41.86,82.39-16.72,168.19-17.73,250.45-.39C823.78,31,906.67,72,985.66,92.83c70.05,18.48,146.53,26.09,214.34,3V0H0V27.35A600.21,600.21,0,0,0,321.39,56.44Z" 
                        fill="currentColor"
                    />
                </svg>
                {/* Subtle gradient overlay */}
                <div className="absolute inset-0 bg-gradient-to-r from-blue-600/5 via-indigo-600/5 to-purple-600/5"></div>
            </div>

            <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-12">
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-12">

                    {/* About Section */}
                    <div className="space-y-6">
                        {/* Logo & Title */}
                        <div className="flex items-center space-x-3">
                            <div className="w-12 h-12 bg-gradient-to-br from-blue-600 to-indigo-700 rounded-xl flex items-center justify-center shadow-lg">
                                <GraduationCap className="w-6 h-6 text-white" />
                            </div>
                            <div>
                                <h2 className="text-xl font-bold text-slate-800">
                                    Forum Information Academy
                                </h2>
                            </div>
                        </div>

                        {/* Description */}
                        <p className="text-slate-600 leading-relaxed">
                            Leading technology education institution dedicated to preparing students for successful careers in the digital economy.
                        </p>

                        {/* Social Media Icons */}
                        <div>
                            <h3 className="text-sm font-semibold text-slate-700 mb-4 uppercase tracking-wide">
                                Follow Us
                            </h3>
                            <div className="flex space-x-3">
                                {socialLinks.map((social, index) => {
                                    const IconComponent = social.icon;
                                    return (
                                        <a
                                            key={index}
                                            href={social.url}
                                            target="_blank"
                                            rel="noopener noreferrer"
                                            className={`group w-12 h-12 ${social.bgColor} rounded-xl flex items-center justify-center transition-all duration-300 hover:shadow-lg hover:scale-110 hover:-translate-y-1`}
                                            title={social.name}
                                        >
                                            <IconComponent className={`w-5 h-5 text-slate-600 transition-all duration-300 ${social.color}`} />
                                        </a>
                                    );
                                })}
                            </div>
                        </div>
                    </div>

                    {/* Quick Links
                    <div className="space-y-6">
                        <h3 className="text-lg font-semibold text-slate-800">Quick Links</h3>
                        <ul className="space-y-3">
                            {[
                                { name: 'Home', path: '/' },
                                { name: 'Programs', path: '/courses' },
                                { name: 'About Us', path: '/about' },
                                { name: 'News & Events', path: '/news' },
                                { name: 'Apply Now', path: '/apply' }
                            ].map((link, index) => (
                                <li key={index}>
                                    <Link 
                                        to={link.path}
                                        className="group flex items-center text-slate-600 hover:text-blue-600 transition-all duration-300"
                                    >
                                        <div className="w-2 h-2 bg-blue-300 rounded-full mr-3 group-hover:bg-blue-600 group-hover:scale-125 transition-all duration-300"></div>
                                        <span className="group-hover:translate-x-1 transition-transform duration-300">
                                            {link.name}
                                        </span>
                                    </Link>
                                </li>
                            ))}
                        </ul>
                    </div> */}

                    {/* Quick Links with Enhanced 3D Hover */}
                    <div className="space-y-6">
                        <h3 className="text-lg font-semibold text-slate-800 flex items-center">
                            <div className="w-6 h-6 bg-gradient-to-br from-blue-500 to-indigo-600 rounded-lg flex items-center justify-center mr-3 shadow-md">
                                <div className="w-2 h-2 bg-white rounded-full animate-pulse"></div>
                            </div>
                            Quick Links
                        </h3>
                        <ul className="space-y-3">
                            {[
                                { name: 'Home', path: '/', icon: '🏠', color: 'from-blue-500 to-cyan-500' },
                                { name: 'Programs', path: '/courses', icon: '📚', color: 'from-green-500 to-emerald-500' },
                                { name: 'About Us', path: '/about', icon: '👥', color: 'from-purple-500 to-pink-500' },
                                { name: 'News & Events', path: '/news', icon: '📰', color: 'from-orange-500 to-red-500' },
                                { name: 'Apply Now', path: '/apply', icon: '🚀', color: 'from-indigo-500 to-purple-500' }
                            ].map((link, index) => (
                                <li key={index} className="perspective-1000">
                                    <Link 
                                        to={link.path}
                                        className="group relative block p-4 rounded-xl bg-white/40 backdrop-blur-sm border border-slate-200/50 transition-all duration-500 hover:bg-white/70 hover:border-blue-300/50 hover:shadow-xl transform-gpu preserve-3d hover:rotate-x-2 hover:rotate-y-4 hover:scale-[1.03] hover:translate-x-2 hover:-translate-y-1"
                                    >
                                        {/* Background Gradient Effect */}
                                        <div className={`absolute inset-0 bg-gradient-to-r ${link.color} opacity-0 group-hover:opacity-10 rounded-xl transition-all duration-500`}></div>

                                        {/* Animated Border */}
                                        <div className="absolute inset-0 rounded-xl border-2 border-transparent group-hover:border-blue-300 transition-all duration-500">
                                            <div className="absolute inset-0 rounded-xl bg-gradient-to-r from-blue-400/0 via-blue-400/50 to-blue-400/0 opacity-0 group-hover:opacity-100 transition-opacity duration-700 animate-pulse"></div>
                                        </div>

                                        {/* Content Container */}
                                        <div className="relative flex items-center space-x-4 z-10">
                                            {/* Enhanced Icon Container */}
                                            <div className="relative">
                                                <div className="w-10 h-10 bg-gradient-to-br from-slate-100 to-slate-200 rounded-lg flex items-center justify-center group-hover:from-blue-100 group-hover:to-blue-200 transition-all duration-500 group-hover:scale-110 group-hover:rotate-12 transform-gpu shadow-md group-hover:shadow-lg">
                                                    <span className="text-lg group-hover:scale-125 transition-transform duration-300">{link.icon}</span>
                                                </div>

                                                {/* Floating Ring */}
                                                <div className="absolute -top-1 -right-1 w-4 h-4 border-2 border-blue-400 rounded-full opacity-0 group-hover:opacity-100 group-hover:animate-spin transition-all duration-500 delay-200">
                                                    <div className="absolute inset-1 bg-blue-400 rounded-full group-hover:animate-pulse"></div>
                                                </div>

                                                {/* Sparkle Effects */}
                                                <div className="absolute -top-0.5 -left-0.5 w-1 h-1 bg-yellow-400 rounded-full opacity-0 group-hover:opacity-100 group-hover:animate-ping transition-opacity duration-500 delay-300"></div>
                                                <div className="absolute -bottom-0.5 -right-0.5 w-1 h-1 bg-cyan-400 rounded-full opacity-0 group-hover:opacity-100 group-hover:animate-pulse transition-opacity duration-500 delay-400"></div>
                                            </div>

                                            {/* Text Content */}
                                            <div className="flex-1">
                                                <span className="text-slate-600 group-hover:text-blue-700 font-medium transition-all duration-300 group-hover:translate-x-2 transform block">
                                                    {link.name}
                                                </span>

                                                {/* Animated Underline */}
                                                <div className="h-0.5 bg-gradient-to-r from-blue-400 to-indigo-500 scale-x-0 group-hover:scale-x-100 transition-transform duration-500 origin-left mt-1 rounded-full"></div>
                                            </div>

                                            {/* Arrow Icon */}
                                            {/* <div className="relative overflow-hidden">
                                                <ArrowRight className="w-5 h-5 text-slate-400 group-hover:text-blue-600 opacity-0 group-hover:opacity-100 group-hover:translate-x-2 group-hover:scale-110 transition-all duration-300 transform" /> */}

                                                {/* Arrow Trail Effect */}
                                                {/* <div className="absolute inset-0 flex items-center justify-center">
                                                    <div className="w-1 h-1 bg-blue-400 rounded-full opacity-0 group-hover:opacity-100 group-hover:animate-ping transition-opacity duration-500 delay-100"></div>
                                                </div>
                                            </div> */}
                                        </div>

                                        {/* Floating Particles */}
                                        <div className="absolute inset-0 overflow-hidden rounded-xl pointer-events-none">
                                            <div className="absolute top-2 left-6 w-0.5 h-0.5 bg-blue-300 rounded-full opacity-0 group-hover:opacity-100 group-hover:animate-bounce transition-opacity duration-500 delay-500"></div>
                                            <div className="absolute top-6 right-8 w-0.5 h-0.5 bg-indigo-300 rounded-full opacity-0 group-hover:opacity-100 group-hover:animate-pulse transition-opacity duration-500 delay-600"></div>
                                            <div className="absolute bottom-3 left-12 w-0.5 h-0.5 bg-purple-300 rounded-full opacity-0 group-hover:opacity-100 group-hover:animate-ping transition-opacity duration-500 delay-700"></div>
                                        </div>

                                        {/* Shimmer Effect */}
                                        <div className="absolute inset-0 bg-gradient-to-r from-transparent via-white/30 to-transparent opacity-0 group-hover:opacity-100 transition-all duration-1000 transform -skew-x-12 translate-x-full group-hover:-translate-x-full rounded-xl"></div>

                                        {/* 3D Shadow Layer */}
                                        <div className="absolute inset-0 bg-slate-200/30 rounded-xl transform translate-z-[-2px] opacity-0 group-hover:opacity-100 transition-opacity duration-300"></div>
                                    </Link>
                                </li>
                            ))}
                        </ul>

                        {/* Decorative Element */}
                        <div className="mt-6 p-4 bg-gradient-to-r from-blue-50 to-indigo-50 rounded-xl border border-blue-200/50">
                            <div className="flex items-center space-x-3">
                                <div className="w-8 h-8 bg-gradient-to-br from-blue-500 to-indigo-600 rounded-lg flex items-center justify-center shadow-md">
                                    <div className="w-3 h-3 bg-white rounded-full animate-pulse"></div>
